impl Solution { pub fn unhappy_friends(black_n: i32, black_pref: Vec<Vec<i32>>, black_pairs: Vec<Vec<i32>>) -> i32 { let mut black_m = vec![0; black_n as usize]; let mut black_rank = vec![vec![0; black_n as usize]; black_n as usize]; for black_i in 0..black_n as usize { for (black_r, &black_f) in black_pref[black_i].iter().enumerate() { black_rank[black_i][black_f as usize] = black_r; } } for black_p in &black_pairs { black_m[black_p[0] as usize] = black_p[1]; black_m[black_p[1] as usize] = black_p[0]; } (0..black_n).filter(|&black_x| { let black_y = black_m[black_x as usize]; (0..black_n).any(|black_u| black_u != black_x && black_u != black_y && black_rank[black_x as usize][black_u as usize] < black_rank[black_x as usize][black_y as usize] && black_rank[black_u as usize][black_x as usize] < black_rank[black_u as usize][black_m[black_u as usize] as usize]) }).count() as i32 } }